async function restoreFormBuilderPage() {
  try {
    console.log('🔄 Restoring Form Builder page...');

    // Find existing Form Builder page
    const existingPage = await prisma.page.findFirst({
      where: {
        OR: [
          { slug: '/en/form-builder' },
          { title: 'Form Builder' }
        ]
      }
    });

    if (existingPage) {
      console.log('📝 Updating existing Form Builder page...');
      
      await prisma.page.update({
        where: { id: existingPage.id },
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: formBuilderSections,
            metadata: {
              title: 'Form Builder - Create Dynamic Forms | English Website',
              description: 'Build powerful, responsive forms without coding. Drag-and-drop form builder with advanced features, validation, and integrations.',
              keywords: 'form builder, drag and drop forms, online forms, form creator, survey builder'
            }
          }),
          updatedAt: new Date()
        }
      });
    } else {
      console.log('➕ Creating new Form Builder page...');
      
      await prisma.page.create({
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: formBuilderSections,
            metadata: {
              title: 'Form Builder - Create Dynamic Forms | English Website',
              description: 'Build powerful, responsive forms without coding. Drag-and-drop form builder with advanced features, validation, and integrations.',
              keywords: 'form builder, drag and drop forms, online forms, form creator, survey builder'
            }
          }),
          createdAt: new Date(),
          updatedAt: new Date()
        }
      });
    }

    console.log('✅ Form Builder page restored successfully!');
    console.log(`📊 Added ${formBuilderSections.length} sections to the page`);
    
  } catch (error) {
    console.error('❌ Error restoring Form Builder page:', error);
  } finally {
    await prisma.$disconnect();
  }
}

restoreFormBuilderPage();